import{_ as a,o as e,c as r,S as i}from"./chunks/framework.C6RQlTYc.js";const p=JSON.parse('{"title":"什么是 AI（人工智能）","description":"","frontmatter":{},"headers":[],"relativePath":"直击概念/17ai/s_ai_1-what_is_ai.md","filePath":"直击概念/17ai/s_ai_1-what_is_ai.md","lastUpdated":1778207238000}'),l={name:"直击概念/17ai/s_ai_1-what_is_ai.md"};function d(o,t,n,s,h,c){return e(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="什么是-ai-人工智能" tabindex="-1">什么是 AI（人工智能） <a class="header-anchor" href="#什么是-ai-人工智能" aria-label="Permalink to &quot;什么是 AI（人工智能）&quot;">​</a></h1><h2 id="概念" tabindex="-1">概念 <a class="header-anchor" href="#概念" aria-label="Permalink to &quot;概念&quot;">​</a></h2><p>人工智能（Artificial Intelligence，AI）是计算机科学的一个分支，旨在<strong>让机器模拟人类的认知能力</strong>，包括学习、推理、感知、理解自然语言和做出决策。简单来说，AI 的目标是让计算机能够执行通常需要人类智能才能完成的任务。</p><p>AI 可分为三个层次：</p><ul><li><strong>弱人工智能（Narrow AI）</strong>：专注于特定任务的 AI，如语音助手、图像识别、推荐系统。当前主流 AI 均属于此类。</li><li><strong>强人工智能（General AI / AGI）</strong>：具备与人类同等水平的通用智能，能处理任何智力任务。目前尚未实现。</li><li><strong>超人工智能（Super AI）</strong>：超越人类所有认知能力的 AI，仍属于理论阶段。</li></ul><h2 id="ai-三大流派" tabindex="-1">AI 三大流派 <a class="header-anchor" href="#ai-三大流派" aria-label="Permalink to &quot;AI 三大流派&quot;">​</a></h2><p>AI 的实现路径主要分为三个流派：</p><ul><li><strong>符号主义（Symbolicism）</strong>：基于逻辑规则和知识库进行推理，如专家系统。优点是可解释性强，缺点是无法处理不确定性和大规模数据。</li><li><strong>连接主义（Connectionism）</strong>：通过模拟神经元网络进行学习，即当前的深度学习。优点是从数据中自动提取特征，缺点是黑箱、依赖大量数据和算力。</li><li><strong>行为主义（Behaviorism）</strong>：通过与环境交互和反馈来学习，如强化学习。AlphaGo 即是典型代表。</li></ul><p>当前 AI 的主流是<strong>连接主义</strong>，大语言模型（LLM）是其最突出的产物。</p><h2 id="关键里程碑" tabindex="-1">关键里程碑 <a class="header-anchor" href="#关键里程碑" aria-label="Permalink to &quot;关键里程碑&quot;">​</a></h2><table><thead><tr><th>时间</th><th>事件</th><th>意义</th></tr></thead><tbody><tr><td>1956</td><td>达特茅斯会议</td><td>AI 概念正式诞生</td></tr><tr><td>1997</td><td>IBM 深蓝击败国际象棋冠军</td><td>符号主义 AI 的高光时刻</td></tr><tr><td>2012</td><td>AlexNet 赢得 ImageNet</td><td>深度学习时代开启</td></tr><tr><td>2016</td><td>AlphaGo 击败李世石</td><td>强化学习+深度学习的里程碑</td></tr><tr><td>2017</td><td>Transformer 论文发表</td><td>大模型时代的基石</td></tr><tr><td>2022</td><td>ChatGPT 发布</td><td>生成式 AI 进入大众视野</td></tr></tbody></table><h2 id="面试常问" tabindex="-1">面试常问 <a class="header-anchor" href="#面试常问" aria-label="Permalink to &quot;面试常问&quot;">​</a></h2><ul><li>AI 与普通程序的区别是什么？</li><li>你了解哪些 AI 在前端的应用场景？举例说明。</li><li>如何看待 AI 对前端开发者的影响？</li></ul><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://aima.cs.berkeley.edu/" target="_blank" rel="noreferrer">Russell &amp; Norvig, Artificial Intelligence: A Modern Approach</a></li><li><a href="https://en.wikipedia.org/wiki/Artificial_intelligence" target="_blank" rel="noreferrer">Wikipedia: Artificial Intelligence</a></li></ul>',15)])])}const u=a(l,[["render",d]]);export{p as __pageData,u as default};
